const INTERVIEW_DATA={"grade3": [{"id": 1, "topic": "Going to the Library", "passage": "Many students go to the library after school. They can read books, study quietly, and use computers there. Some students borrow books to read at home. Libraries are free to use and open to everyone.", "illustration": "A boy is sitting at a desk in a library. He is reading a book. On the desk, there are two more books and a pencil. A librarian is standing nearby, helping another student.", "questions": [{"q": "According to the passage, what can students do at the library?", "model": "They can read books, study quietly, and use computers.", "keywords": ["read", "books", "study", "computers", "quietly"]}, {"q": "According to the passage, why do some students borrow books?", "model": "Because they want to read them at home.", "keywords": ["home", "read", "borrow"]}, {"q": "Please look at the picture. What is the boy doing?", "model": "He is reading a book at a desk.", "keywords": ["reading", "book", "desk", "sitting"]}, {"q": "Do you often go to the library?", "model": "Yes, I go to the library once a week to study and borrow books. / No, I don't go often, but I sometimes visit to use the computers.", "keywords": ["library", "study", "books", "sometimes", "often"]}, {"q": "Today, many people read books on electronic devices instead of paper books. Do you think this is a good thing?", "model": "Yes, I think it is good because you can carry many books at once and they are easy to read anywhere. / No, I prefer paper books because they are easier on the eyes.", "keywords": ["good", "books", "easy", "carry", "prefer", "eyes", "digital", "electronic"]}]}, {"id": 2, "topic": "School Sports Day", "passage": "Sports day is one of the most popular school events in Japan. Students practise for weeks before the event. They run races, play team games, and cheer for their classmates. Parents often come to watch.", "illustration": "A group of students are running in a race on a school field. Some students are cheering on the side. A teacher is standing at the finish line with a stopwatch.", "questions": [{"q": "According to the passage, how long do students practise before sports day?", "model": "They practise for weeks.", "keywords": ["weeks", "practise", "practice", "before"]}, {"q": "According to the passage, who often comes to watch sports day?", "model": "Parents often come to watch.", "keywords": ["parents", "watch", "come"]}, {"q": "Please look at the picture. What are the students doing?", "model": "Some students are running in a race, and others are cheering.", "keywords": ["running", "race", "cheering", "field"]}, {"q": "Do you enjoy sports day at your school?", "model": "Yes, I enjoy it very much. I like running and cheering for my friends. / No, I am not very good at sports, but I enjoy cheering for my classmates.", "keywords": ["enjoy", "sports", "running", "friends", "cheering", "classmates"]}, {"q": "Some people say children should have more physical exercise at school. Do you agree?", "model": "Yes, I agree because exercise is important for health and it helps students concentrate better in class.", "keywords": ["agree", "exercise", "health", "important", "concentrate", "class", "physical"]}]}, {"id": 3, "topic": "Cooking at Home", "passage": "More young people are learning to cook at home. Cooking is a useful skill for everyday life. People who cook at home can save money and eat healthier food. Some people enjoy cooking as a hobby.", "illustration": "A teenage girl is standing in a kitchen. She is cutting vegetables on a chopping board. There is a pot on the stove. Her mother is watching and smiling.", "questions": [{"q": "According to the passage, what are two benefits of cooking at home?", "model": "People can save money and eat healthier food.", "keywords": ["save", "money", "healthier", "healthy", "food"]}, {"q": "According to the passage, why do some people cook at home?", "model": "Because they enjoy it as a hobby.", "keywords": ["hobby", "enjoy", "fun"]}, {"q": "Please look at the picture. What is the girl doing?", "model": "She is cutting vegetables in the kitchen.", "keywords": ["cutting", "vegetables", "kitchen", "chopping"]}, {"q": "Do you help with cooking at home?", "model": "Yes, I sometimes help my mother cook dinner. I enjoy making simple dishes. / No, I don't cook very often, but I would like to learn.", "keywords": ["help", "cook", "dinner", "simple", "learn", "mother"]}, {"q": "Do you think it is important for young people to learn how to cook?", "model": "Yes, I think cooking is an important life skill. It helps people save money and stay healthy.", "keywords": ["important", "skill", "healthy", "save", "money", "life"]}]}, {"id": 4, "topic": "Using Smartphones", "passage": "Most teenagers in Japan own a smartphone. They use them to communicate with friends, watch videos, and study. However, spending too much time on smartphones can be bad for health and sleep.", "illustration": "A boy is sitting on a sofa, looking at his smartphone. There is a clock on the wall showing 11 PM. His school bag and books are on the table next to him.", "questions": [{"q": "According to the passage, what do teenagers use smartphones for?", "model": "They use them to communicate with friends, watch videos, and study.", "keywords": ["communicate", "friends", "videos", "study", "watch"]}, {"q": "According to the passage, what can be a problem with using smartphones too much?", "model": "It can be bad for health and sleep.", "keywords": ["health", "sleep", "bad", "problem"]}, {"q": "Please look at the picture. What is the boy doing, and what time is it?", "model": "He is using his smartphone late at night. It is 11 PM.", "keywords": ["smartphone", "night", "eleven", "late", "sofa"]}, {"q": "How many hours a day do you use your smartphone?", "model": "I use my smartphone for about two or three hours a day, mainly for studying and messaging friends.", "keywords": ["hours", "day", "study", "messages", "friends"]}, {"q": "Do you think students should be allowed to bring smartphones to school?", "model": "Yes, because smartphones can be useful for studying and looking up information. / No, because they can be a distraction in class.", "keywords": ["school", "study", "distraction", "class", "useful", "allowed", "information"]}]}, {"id": 5, "topic": "Travelling Abroad", "passage": "Many Japanese students are interested in travelling abroad. Visiting other countries helps people learn about different cultures and languages. Some students join study abroad programmes to improve their English skills.", "illustration": "A young woman is standing in front of a famous foreign landmark. She is holding a map and smiling. There are other tourists around her taking photos.", "questions": [{"q": "According to the passage, what can people learn by visiting other countries?", "model": "They can learn about different cultures and languages.", "keywords": ["cultures", "languages", "different", "learn"]}, {"q": "According to the passage, why do some students join study abroad programmes?", "model": "To improve their English skills.", "keywords": ["English", "improve", "skills", "study abroad"]}, {"q": "Please look at the picture. What is the woman doing?", "model": "She is looking at a map in front of a famous landmark.", "keywords": ["map", "landmark", "standing", "smiling", "tourists"]}, {"q": "Have you ever travelled abroad? If not, where would you like to go?", "model": "Yes, I have been to Australia. It was very exciting. / No, but I would love to visit the UK because I want to improve my English.", "keywords": ["travelled", "abroad", "visit", "English", "exciting", "country"]}, {"q": "Do you think studying abroad is a good experience for young people?", "model": "Yes, I think it is a wonderful experience. Students can improve their language skills and learn about other cultures.", "keywords": ["good", "experience", "language", "cultures", "improve", "wonderful"]}]}, {"id": 6, "topic": "Environmental Problems", "passage": "Environmental problems such as pollution and global warming are serious issues today. People can help the environment by recycling and using less plastic. Small actions by many people can make a big difference.", "illustration": "Two students are picking up rubbish in a park. They are wearing gloves and holding rubbish bags. There are trees and flowers around them. A sign says 'Keep the park clean.'", "questions": [{"q": "According to the passage, what are two environmental problems mentioned?", "model": "Pollution and global warming.", "keywords": ["pollution", "global warming"]}, {"q": "According to the passage, how can people help the environment?", "model": "By recycling and using less plastic.", "keywords": ["recycling", "recycle", "plastic", "less"]}, {"q": "Please look at the picture. What are the students doing?", "model": "They are picking up rubbish in a park.", "keywords": ["picking", "rubbish", "park", "trash", "garbage", "cleaning"]}, {"q": "What do you do to help the environment?", "model": "I try to recycle cans and bottles. I also turn off lights when I leave a room to save electricity.", "keywords": ["recycle", "electricity", "lights", "save", "bottles", "cans"]}, {"q": "Do you think the government should do more to protect the environment?", "model": "Yes, I think the government should make stricter rules about pollution and support clean energy.", "keywords": ["government", "environment", "rules", "pollution", "energy", "protect", "clean"]}]}, {"id": 7, "topic": "Part-time Jobs", "passage": "Many high school students in Japan work part-time. They work at convenience stores, restaurants, or supermarkets. Working part-time helps students earn money and learn responsibility. However, they must balance work and study carefully.", "illustration": "A teenage boy is working at a convenience store. He is standing behind a counter and handing a bag to a customer. He is wearing a uniform and smiling.", "questions": [{"q": "According to the passage, where do some students work part-time?", "model": "At convenience stores, restaurants, or supermarkets.", "keywords": ["convenience", "stores", "restaurants", "supermarkets"]}, {"q": "According to the passage, what must students be careful about when working part-time?", "model": "They must balance work and study carefully.", "keywords": ["balance", "work", "study", "careful"]}, {"q": "Please look at the picture. What is the boy doing?", "model": "He is working at a convenience store and serving a customer.", "keywords": ["working", "convenience", "store", "customer", "counter", "serving"]}, {"q": "Do you have a part-time job, or would you like to have one?", "model": "No, I don't have one yet, but I would like to work at a cafe to earn some money and gain experience. / Yes, I work at a supermarket on weekends.", "keywords": ["job", "work", "earn", "money", "experience", "weekends"]}, {"q": "Do you think part-time work is beneficial for students?", "model": "Yes, I think it teaches students responsibility and helps them understand the value of money.", "keywords": ["responsibility", "money", "value", "beneficial", "teaches", "experience"]}]}, {"id": 8, "topic": "Social Media", "passage": "Social media platforms are very popular among young people. People use them to share photos, news, and opinions. While social media helps people stay connected, it can also spread false information.", "illustration": "A teenage girl is sitting at a desk, using a laptop. She is smiling and looking at a social media page. There are many colourful posts on the screen.", "questions": [{"q": "According to the passage, what do people share on social media?", "model": "They share photos, news, and opinions.", "keywords": ["photos", "news", "opinions", "share"]}, {"q": "According to the passage, what is one problem with social media?", "model": "It can spread false information.", "keywords": ["false", "information", "fake", "spread"]}, {"q": "Please look at the picture. What is the girl doing?", "model": "She is using a laptop to look at social media.", "keywords": ["laptop", "social media", "sitting", "desk", "looking"]}, {"q": "Do you use social media? Which platform do you prefer?", "model": "Yes, I use Instagram to share photos with friends. I also use Twitter to read news and see what is trending.", "keywords": ["Instagram", "Twitter", "photos", "friends", "news", "use"]}, {"q": "Do you think social media has more positive or negative effects on society?", "model": "I think it has both, but overall more positive effects because it helps people connect and share information quickly.", "keywords": ["positive", "negative", "connect", "information", "share", "society"]}]}, {"id": 9, "topic": "Healthy Eating", "passage": "Eating healthy food is important for a good life. Many doctors say people should eat more vegetables and fruits and less junk food. A balanced diet helps the body stay strong and the mind stay focused.", "illustration": "A woman is at a farmers' market. She is choosing fresh vegetables from a stall. The stall has many colourful fruits and vegetables. The seller is handing her some tomatoes.", "questions": [{"q": "According to the passage, what do doctors say people should eat more of?", "model": "More vegetables and fruits.", "keywords": ["vegetables", "fruits", "more"]}, {"q": "According to the passage, what are the benefits of a balanced diet?", "model": "It helps the body stay strong and the mind stay focused.", "keywords": ["strong", "focused", "body", "mind", "balanced"]}, {"q": "Please look at the picture. What is the woman doing?", "model": "She is buying vegetables at a farmers' market.", "keywords": ["vegetables", "market", "buying", "choosing", "fresh"]}, {"q": "Do you think you eat a healthy diet?", "model": "I try to eat healthily, but I sometimes eat too much junk food. I am trying to eat more vegetables and less sugar.", "keywords": ["healthy", "vegetables", "junk", "food", "sugar", "try"]}, {"q": "Should schools teach students more about healthy eating?", "model": "Yes, I think schools should have more nutrition classes so students learn what to eat to stay healthy.", "keywords": ["schools", "teach", "nutrition", "healthy", "learn", "class"]}]}, {"id": 10, "topic": "Music and Hobbies", "passage": "Having hobbies is important for mental health and relaxation. Many young people enjoy listening to music, drawing, or playing sports in their free time. Hobbies also help people make new friends with similar interests.", "illustration": "A boy is playing the guitar in his bedroom. He has sheet music in front of him. There are posters of bands on the wall. His friend is sitting nearby, listening and smiling.", "questions": [{"q": "According to the passage, why are hobbies important?", "model": "They are important for mental health and relaxation.", "keywords": ["mental", "health", "relaxation", "important"]}, {"q": "According to the passage, how can hobbies help people socially?", "model": "They help people make new friends with similar interests.", "keywords": ["friends", "similar", "interests", "new", "make"]}, {"q": "Please look at the picture. What is the boy doing?", "model": "He is playing the guitar in his bedroom.", "keywords": ["playing", "guitar", "bedroom", "sheet music"]}, {"q": "What are your hobbies and why do you enjoy them?", "model": "I enjoy reading and playing badminton. Reading helps me relax, and badminton keeps me fit and is fun to play with friends.", "keywords": ["enjoy", "relax", "fit", "fun", "friends", "hobby", "hobbies"]}, {"q": "Do you think it is important to have hobbies outside of studying?", "model": "Yes, I think hobbies are very important. They help reduce stress and give students something to look forward to.", "keywords": ["stress", "reduce", "important", "balance", "look forward", "studying"]}]}], "pre2": [{"id": 1, "topic": "Technology in the Workplace", "passage": "The internet has changed how many people do their jobs. More companies now allow employees to work from home using computers and video calls. This gives workers more flexibility, but some people find it harder to separate their work life from their personal life when working at home.", "illustration_1": "A woman is sitting at a home desk, attending a video meeting on her laptop. Several colleagues appear on the screen. She has a notebook and coffee next to her.", "illustration_2": "The same woman is cooking dinner in the kitchen, but her laptop is open on the counter and she keeps looking at work emails. She looks stressed and tired.", "questions": [{"q": "According to the passage, what has changed about how people work?", "model": "More companies now allow employees to work from home using computers and video calls.", "keywords": ["computers", "video calls", "remote", "work from home", "companies"]}, {"q": "According to the passage, what is one problem with working from home?", "model": "Some people find it harder to separate their work life from their personal life.", "keywords": ["separate", "work", "personal", "life", "balance", "harder", "difficult"]}, {"q": "Please look at picture 1. What is the woman doing?", "model": "She is working from home and attending a video meeting with her colleagues.", "keywords": ["video", "meeting", "colleagues", "laptop", "home", "working"]}, {"q": "Please look at picture 2. What do you think will happen next?", "model": "She will probably continue to check her emails even while cooking, making it difficult for her to relax and enjoy her personal time.", "keywords": ["emails", "work", "stressed", "relax", "personal time", "continue", "difficult"]}, {"q": "Do you think working from home is better than going to the office? Please give a reason for your opinion.", "model": "I think working from home has advantages because people save commuting time and can work more flexibly. However, it can be difficult to concentrate at home.", "keywords": ["home", "office", "commute", "flexible", "concentrate", "disadvantage"]}]}, {"id": 2, "topic": "Museums and Technology", "passage": "Recently, museums have started to use information technology in new ways. Many museums now offer virtual tours online so that people around the world can visit without travelling. Interactive displays and apps also help make exhibitions more engaging, especially for younger visitors.", "illustration_1": "A family is standing in a museum, using tablets to interact with a digital display. The display shows 3D images of ancient artefacts. The children look excited and engaged.", "illustration_2": "A teenager is at home, using a laptop to take a virtual museum tour. She is wearing headphones and looking closely at the screen. She is taking notes in a notebook.", "questions": [{"q": "According to the passage, how can people visit museums without travelling?", "model": "They can take virtual tours online.", "keywords": ["virtual", "tours", "online", "internet", "without travelling"]}, {"q": "According to the passage, how do apps and interactive displays benefit museums?", "model": "They make exhibitions more engaging, especially for younger visitors.", "keywords": ["engaging", "younger", "visitors", "interactive", "displays"]}, {"q": "Please look at picture 1. What is the family doing?", "model": "The family is using tablets to look at interactive digital displays in a museum.", "keywords": ["tablets", "interactive", "museum", "digital", "displays", "children"]}, {"q": "Please look at picture 2. What do you think the girl will do with her notes?", "model": "She will probably use her notes for studying or a school project about what she saw in the virtual museum.", "keywords": ["notes", "study", "project", "school", "learning", "museum"]}, {"q": "Do you think virtual museum tours can replace visiting a museum in person? Please give a reason.", "model": "No, I don't think they can fully replace real visits because you cannot see the actual size of objects or feel the atmosphere of the museum. But virtual tours are useful for people who cannot travel.", "keywords": ["replace", "real", "atmosphere", "useful", "travel", "size", "experience", "person"]}]}, {"id": 3, "topic": "Subscription Services", "passage": "These days, subscription services for music, movies, and software are becoming more common. Instead of buying products, people pay a monthly fee to use them. This can be more convenient and cost-effective, but it also means that people do not actually own what they pay for.", "illustration_1": "A young man is sitting on a sofa, happily watching a streaming service on a large TV. He has popcorn next to him. On the screen, there is a wide selection of films.", "illustration_2": "The same man is on his phone, looking worried at a notification that says his subscription has been cancelled due to a payment issue. He is holding his credit card.", "questions": [{"q": "According to the passage, how do subscription services work?", "model": "Instead of buying products, people pay a monthly fee to use them.", "keywords": ["monthly", "fee", "pay", "instead", "buying", "products"]}, {"q": "According to the passage, what is one disadvantage of subscription services?", "model": "People do not actually own what they pay for.", "keywords": ["do not own", "pay", "disadvantage"]}, {"q": "Please look at picture 1. What is the man doing?", "model": "He is watching a streaming service on TV at home.", "keywords": ["watching", "streaming", "TV", "sofa", "films", "movies"]}, {"q": "Please look at picture 2. What do you think the man will do next?", "model": "He will probably try to fix the payment problem by updating his credit card information so he can continue using the service.", "keywords": ["payment", "credit card", "fix", "update", "continue", "subscription", "worried"]}, {"q": "Do you think subscription services are a good way to access entertainment? Please give a reason.", "model": "Yes, I think they are convenient because you can access a huge variety of content for a fixed monthly price. However, if you subscribe to too many services, it can become expensive.", "keywords": ["convenient", "variety", "content", "monthly", "expensive", "access", "fixed"]}]}, {"id": 4, "topic": "Pets in Modern Society", "passage": "Recently, more people in Japan are choosing to have pets such as cats and dogs. Pets can provide companionship and reduce stress for their owners. However, owning a pet requires a lot of time, money, and responsibility, and some people are not fully prepared for this.", "illustration_1": "An elderly woman is sitting in a park, playing with her small dog. She is smiling and looks very happy. Other people in the park are also watching and smiling.", "illustration_2": "A young couple is looking stressed in their apartment. Their dog has chewed up a shoe and knocked over some books. The dog is sitting in the middle of the mess.", "questions": [{"q": "According to the passage, what are two benefits of having a pet?", "model": "Pets can provide companionship and reduce stress.", "keywords": ["companionship", "reduce", "stress", "company", "lonely", "benefits"]}, {"q": "According to the passage, what do some people fail to do before getting a pet?", "model": "Some people are not fully prepared for the time, money, and responsibility involved.", "keywords": ["prepared", "responsible", "responsibility", "time", "money", "ready"]}, {"q": "Please look at picture 1. What is the woman doing and how does she feel?", "model": "She is playing with her dog in the park, and she looks very happy.", "keywords": ["playing", "dog", "park", "happy", "smiling", "elderly"]}, {"q": "Please look at picture 2. What do you think the couple will do to solve this problem?", "model": "They will probably train their dog or find ways to keep it occupied so it does not destroy things in the apartment.", "keywords": ["training", "occupy", "toys", "solve", "behave", "problem", "apartment"]}, {"q": "Do you think people should have to take a course before getting a pet? Please give your opinion.", "model": "Yes, I think a short course would help people understand the responsibilities involved and ensure pets are properly cared for.", "keywords": ["course", "responsible", "understand", "care", "prepare", "ensure", "properly"]}]}, {"id": 5, "topic": "Environmental Awareness", "passage": "Today, people in Japan are using fewer plastic shopping bags. In 2020, Japan introduced a law requiring shops to charge for plastic bags. This was designed to reduce plastic waste and encourage people to use reusable bags. Many people have changed their habits as a result.", "illustration_1": "A woman is at a supermarket checkout. She is paying for her groceries and handing over a reusable fabric bag. The cashier is putting items into the bag.", "illustration_2": "A beach clean-up event is taking place. Volunteers are picking up plastic bottles and rubbish from the sand. Children and adults are working together. A banner reads 'Save Our Ocean.'", "questions": [{"q": "According to the passage, what law did Japan introduce in 2020?", "model": "A law requiring shops to charge for plastic bags.", "keywords": ["law", "charge", "plastic bags", "shops", "2020", "fee"]}, {"q": "According to the passage, what was the purpose of the new law?", "model": "To reduce plastic waste and encourage people to use reusable bags.", "keywords": ["reduce", "plastic", "waste", "reusable", "encourage", "bags"]}, {"q": "Please look at picture 1. What is the woman doing?", "model": "She is using a reusable bag at the supermarket instead of a plastic bag.", "keywords": ["reusable", "bag", "supermarket", "checkout", "groceries", "paying"]}, {"q": "Please look at picture 2. What do you think will happen if more people join events like this?", "model": "The beaches and oceans will become cleaner, which will help protect marine animals and the environment.", "keywords": ["ocean", "marine", "animals", "environment", "protect", "beaches", "cleaner"]}, {"q": "Do you think individuals or governments have a greater responsibility to reduce plastic waste? Please give a reason.", "model": "I think both have a responsibility. Governments can make laws and policies, but individuals must also change their daily habits to reduce waste.", "keywords": ["government", "individual", "responsibility", "laws", "habits", "reduce", "policies", "daily"]}]}, {"id": 6, "topic": "Traditional Crafts", "passage": "These days, traditional Japanese crafts such as pottery, textiles, and papermaking are being taught online. This allows artisans to share their skills with people around the world. However, some experts worry that online teaching cannot fully replace learning traditional techniques in person.", "illustration_1": "An elderly craftsman is demonstrating pottery techniques in a small workshop. A young woman is watching closely and trying to copy the technique with her own clay.", "illustration_2": "A person is watching an online pottery tutorial on a laptop at home. They are following along using their own clay and tools. There is a mess on the table.", "questions": [{"q": "According to the passage, how are traditional crafts being shared today?", "model": "They are being taught online, allowing artisans to share their skills with people around the world.", "keywords": ["online", "internet", "world", "artisans", "share", "taught", "skills"]}, {"q": "According to the passage, what concern do some experts have about online teaching?", "model": "They worry that online teaching cannot fully replace learning traditional techniques in person.", "keywords": ["replace", "in person", "techniques", "traditional", "fully", "worry", "concern"]}, {"q": "Please look at picture 1. What is happening in the workshop?", "model": "An elderly craftsman is teaching a young woman how to make pottery.", "keywords": ["craftsman", "teaching", "pottery", "clay", "workshop", "learning", "young woman"]}, {"q": "Please look at picture 2. What are the challenges the person at home might face?", "model": "They might find it difficult to get proper feedback on their technique without a teacher present in person.", "keywords": ["feedback", "teacher", "difficult", "technique", "in person", "guidance", "alone"]}, {"q": "Do you think learning traditional crafts is important in modern society? Please give a reason.", "model": "Yes, I think it is important to preserve traditional crafts because they are part of Japan's cultural heritage and would be lost if nobody continued them.", "keywords": ["preserve", "cultural", "heritage", "important", "traditional", "lost", "continue", "society"]}]}, {"id": 7, "topic": "Wild Animals and Farming", "passage": "Recently, many farmers in Japan's countryside have been struggling to protect their crops from wild animals such as deer and boar. These animals enter farmland and destroy crops, causing serious financial losses. Some communities have introduced new methods to keep animals away from farmland.", "illustration_1": "A farmer is standing in his field, looking worried at damaged crops. There are tracks in the soil and broken plants. A deer can be seen in the background near the edge of the field.", "illustration_2": "Workers are installing a tall electric fence around a field of vegetables. A farmer is watching and talking with the workers. Other farmers are observing nearby.", "questions": [{"q": "According to the passage, what problem are farmers facing?", "model": "Wild animals such as deer and boar are entering farmland and destroying their crops.", "keywords": ["wild animals", "deer", "boar", "crops", "destroy", "farmland", "damage"]}, {"q": "According to the passage, what effect does this have on farmers?", "model": "It causes serious financial losses.", "keywords": ["financial", "losses", "money", "serious", "economic"]}, {"q": "Please look at picture 1. What has happened to the farmer's crops?", "model": "Wild animals have entered his field and destroyed some of the crops.", "keywords": ["damaged", "destroyed", "crops", "deer", "tracks", "worried", "field"]}, {"q": "Please look at picture 2. What do you think will happen after the fence is installed?", "model": "The fence will prevent wild animals from entering the field, so the farmer will be able to protect his crops and reduce financial losses.", "keywords": ["prevent", "protect", "crops", "reduce", "losses", "fence", "animals", "safe"]}, {"q": "Do you think the government should do more to help farmers deal with this problem? Please give a reason.", "model": "Yes, I think the government should provide financial support for protective measures like fences, as farmers cannot always afford them on their own.", "keywords": ["government", "support", "financial", "farmers", "afford", "help", "measures", "fences"]}]}, {"id": 8, "topic": "Health and Face Masks", "passage": "People in Japan have long used face masks to protect their health, particularly during cold and flu seasons. In recent years, wearing masks has become even more common. While masks can help prevent the spread of illness, some researchers suggest that wearing them too often may affect children's ability to develop social skills.", "illustration_1": "A teacher is standing in front of a class. All the students and the teacher are wearing masks. The teacher is writing on the board and the students are listening.", "illustration_2": "Two young children are playing outside without masks. One child is smiling at the other, who is laughing. They are communicating and making facial expressions freely.", "questions": [{"q": "According to the passage, why have people in Japan long worn face masks?", "model": "To protect their health, particularly during cold and flu seasons.", "keywords": ["health", "cold", "flu", "protect", "seasons", "illness"]}, {"q": "According to the passage, what concern do some researchers have about wearing masks?", "model": "They suggest that wearing masks too often may affect children's ability to develop social skills.", "keywords": ["social skills", "children", "develop", "affect", "concern", "too often"]}, {"q": "Please look at picture 1. What is happening in the classroom?", "model": "The teacher and all the students are wearing face masks in class.", "keywords": ["masks", "classroom", "teacher", "students", "wearing", "lesson"]}, {"q": "Please look at picture 2. What advantage do the children have by not wearing masks?", "model": "They can communicate more naturally using facial expressions, which helps them develop social and emotional skills.", "keywords": ["facial expressions", "communicate", "naturally", "social", "emotional", "skills", "freely"]}, {"q": "Do you think wearing masks in schools should be made optional? Please give your opinion with a reason.", "model": "Yes, I think it should be optional because children need to see facial expressions to develop communication skills, especially at a young age.", "keywords": ["optional", "children", "expressions", "communication", "young", "develop", "skills"]}]}, {"id": 9, "topic": "Climate Change and Energy", "passage": "Climate change has become one of the most serious global issues of the 21st century. Rising temperatures are causing more extreme weather events such as floods and droughts. Many countries are now investing in renewable energy sources such as solar and wind power to reduce their dependence on fossil fuels.", "illustration_1": "Engineers are working at a large solar panel farm in a dry, sunny region. There are rows of solar panels stretching into the distance. A wind turbine can be seen in the background.", "illustration_2": "A neighbourhood is flooded after a severe storm. Residents are evacuating their homes by boat. Emergency vehicles are parked on higher ground. People look worried.", "questions": [{"q": "According to the passage, what effects is climate change having?", "model": "It is causing rising temperatures and more extreme weather events such as floods and droughts.", "keywords": ["temperatures", "floods", "droughts", "extreme", "weather", "rising", "events"]}, {"q": "According to the passage, what are countries doing to address climate change?", "model": "They are investing in renewable energy sources such as solar and wind power.", "keywords": ["renewable", "solar", "wind", "energy", "investing", "fossil fuels"]}, {"q": "Please look at picture 1. What is happening at this location?", "model": "Engineers are working at a solar panel farm to generate clean renewable energy.", "keywords": ["solar", "panels", "energy", "renewable", "wind turbine", "engineers", "clean"]}, {"q": "Please look at picture 2. What might happen to the people in this neighbourhood in the future if climate change continues?", "model": "They may face more frequent and severe flooding, forcing them to evacuate their homes more often and causing greater damage to the community.", "keywords": ["flooding", "evacuate", "severe", "frequent", "damage", "future", "worse", "continue"]}, {"q": "Do you think individuals can make a meaningful difference in fighting climate change? Please give a reason.", "model": "Yes, I think individuals can make a difference by reducing their energy use, recycling, and choosing sustainable products. Small changes by many people add up.", "keywords": ["reduce", "energy", "recycle", "sustainable", "difference", "individual", "choices", "meaningful"]}]}, {"id": 10, "topic": "Artificial Intelligence", "passage": "Artificial intelligence, or AI, is rapidly changing many industries. AI can now perform tasks that once required human workers, such as analysing data, writing reports, and even creating artwork. While AI increases efficiency, there are growing concerns about its impact on employment and the role of human creativity.", "illustration_1": "A person is working at a computer in an office. On the screen, an AI tool is automatically generating a detailed report. The person is reviewing the results with a satisfied expression.", "illustration_2": "A group of office workers are having a discussion. One person is pointing at a notice on the board that says 'AI System Replacing 30% of Tasks'. Some workers look concerned.", "questions": [{"q": "According to the passage, what kinds of tasks can AI now perform?", "model": "It can analyse data, write reports, and even create artwork.", "keywords": ["data", "reports", "artwork", "analyse", "write", "create", "tasks"]}, {"q": "According to the passage, what concerns do people have about AI?", "model": "There are concerns about its impact on employment and the role of human creativity.", "keywords": ["employment", "jobs", "creativity", "human", "concerns", "impact", "role"]}, {"q": "Please look at picture 1. How is AI being used in this office?", "model": "An AI tool is automatically generating a report, which the worker is reviewing.", "keywords": ["report", "generating", "AI", "automatically", "reviewing", "office", "tool"]}, {"q": "Please look at picture 2. How might the workers be feeling, and why?", "model": "They might be feeling worried or anxious because they are concerned that AI will replace their jobs.", "keywords": ["worried", "anxious", "concerned", "replace", "jobs", "AI", "nervous"]}, {"q": "Do you think AI will create more problems or more opportunities for people in the future? Please give a reason.", "model": "I think AI will create both. While some jobs may disappear, new roles will emerge that require people to work alongside AI. The key is education and adaptability.", "keywords": ["opportunities", "problems", "jobs", "education", "adaptability", "new", "roles", "future"]}]}],"pre2plus":[{"id":1,"topic":"Recycling at Home","passage":"Today, many families try to recycle at home. They separate paper, plastic, and cans into different boxes. Some people also make compost from food waste in their gardens. By doing these things, families can reduce the amount of garbage they throw away. Recycling is a simple way for everyone to help protect the environment.","illustration_1":"A boy and a girl are standing in a kitchen. The boy is putting plastic bottles into a blue box, and the girl is putting old newspapers into a paper box.","illustration_2":"A woman is in a garden. She is pouring food waste into a compost bin, and a small dog is watching her.","questions":[{"q":"According to the passage, how can families reduce the amount of garbage they throw away?","model":"By recycling paper, plastic, and cans, and by making compost from food waste.","keywords":["recycling","compost","garbage","reduce","waste"]},{"q":"Please look at illustration 1. What are the boy and the girl doing?","model":"The boy is putting plastic bottles into a blue box, and the girl is putting old newspapers into a paper box.","keywords":["boy","girl","bottles","newspapers","box"]},{"q":"Please look at illustration 2. What is the woman doing?","model":"She is pouring food waste into a compost bin while a dog watches her.","keywords":["woman","food","waste","compost","bin"]},{"q":"Do you often recycle things at home?","model":"Yes, I do. I always separate cans and bottles from other garbage. / No, I don't. My family usually throws most things in the same bin.","keywords":["yes","recycle","separate","cans","bottles"]},{"q":"Some people say schools should teach children more about recycling. What do you think?","model":"I agree. If children learn about recycling early, they will protect the environment when they grow up. / I disagree. Children should learn it at home from their parents instead.","keywords":["agree","children","learn","environment","school"]}]},{"id":2,"topic":"Online Shopping","passage":"Online shopping has become very popular in recent years. People can buy clothes, books, and food from home using their smartphones or computers. The items are usually delivered to their houses in a few days. Online shopping is convenient because stores are open all day and night. However, some people worry that they cannot check the products before buying them.","illustration_1":"A man is sitting on a sofa with a laptop. He is looking at a pair of shoes on the screen and holding a credit card in his other hand.","illustration_2":"A delivery worker is standing at a front door. He is handing a large box to a smiling woman.","questions":[{"q":"According to the passage, why is online shopping convenient?","model":"Because stores are open all day and night, so people can buy things anytime from home.","keywords":["convenient","stores","open","home","anytime"]},{"q":"Please look at illustration 1. What is the man doing?","model":"He is sitting on a sofa and looking at a pair of shoes on his laptop while holding a credit card.","keywords":["man","sofa","laptop","shoes","credit"]},{"q":"Please look at illustration 2. What is the delivery worker doing?","model":"He is handing a large box to a smiling woman at her front door.","keywords":["delivery","worker","box","woman","door"]},{"q":"Do you like to shop online?","model":"Yes, I do. It is easy to compare prices and buy things quickly. / No, I don't. I prefer to see and touch the products in a real store.","keywords":["yes","online","easy","prices","quickly"]},{"q":"Some people say that shopping in real stores is better than shopping online. What do you think?","model":"I agree. In real stores, you can try things on and take them home right away. / I disagree. Online shopping is cheaper and saves a lot of time.","keywords":["agree","stores","try","online","time"]}]},{"id":3,"topic":"School Clubs","passage":"Many students in Japan join clubs at their schools. There are sports clubs like soccer and tennis, and culture clubs like music and art. Students practice with their club members after class almost every day. Joining a club is a good way to make friends and learn new skills. Some students say club activities are the best part of their school life.","illustration_1":"Three students are on a school field. Two boys are kicking a soccer ball, and a girl is running toward the goal.","illustration_2":"In a music room, a girl is playing the piano, and two boys are playing the guitar and the drums together.","questions":[{"q":"According to the passage, why is joining a club a good idea?","model":"Because it is a good way to make friends and learn new skills.","keywords":["club","friends","learn","skills","join"]},{"q":"Please look at illustration 1. What are the students doing?","model":"Two boys are kicking a soccer ball, and a girl is running toward the goal.","keywords":["boys","kicking","soccer","girl","running"]},{"q":"Please look at illustration 2. What are the students doing in the music room?","model":"A girl is playing the piano, and two boys are playing the guitar and the drums.","keywords":["girl","piano","boys","guitar","drums"]},{"q":"Do you belong to any club at your school?","model":"Yes, I do. I am in the tennis club and I practice three times a week. / No, I don't. I go home early to study and help my family.","keywords":["yes","club","practice","tennis","school"]},{"q":"Some people say that sports clubs are more useful than culture clubs. What do you think?","model":"I agree. Sports clubs keep students healthy and teach teamwork. / I disagree. Culture clubs help students grow their talents and creativity.","keywords":["agree","sports","healthy","culture","talents"]}]},{"id":4,"topic":"Healthy Eating","passage":"Eating healthy food is important for a strong body and mind. Doctors say that people should eat a lot of vegetables and fruit every day. They also say that people should not eat too much fast food or sweets. Cooking meals at home is one good way to eat well. When people eat healthy food, they often feel more energetic and get sick less often.","illustration_1":"A mother and her son are in the kitchen. The mother is cutting vegetables, and the boy is washing tomatoes at the sink.","illustration_2":"A group of friends is at a fast-food restaurant. They are eating hamburgers and drinking soda, and one boy looks tired.","questions":[{"q":"According to the passage, what do doctors say people should eat every day?","model":"They say people should eat a lot of vegetables and fruit every day.","keywords":["doctors","vegetables","fruit","eat","every"]},{"q":"Please look at illustration 1. What are the mother and her son doing?","model":"The mother is cutting vegetables, and the boy is washing tomatoes at the sink.","keywords":["mother","cutting","vegetables","boy","washing"]},{"q":"Please look at illustration 2. What are the friends doing?","model":"They are eating hamburgers and drinking soda at a fast-food restaurant.","keywords":["friends","eating","hamburgers","soda","restaurant"]},{"q":"Do you try to eat healthy food?","model":"Yes, I do. I eat a salad and fruit almost every day. / No, I don't. I love snacks and sweet drinks too much.","keywords":["yes","healthy","eat","fruit","salad"]},{"q":"Some people say that eating out is worse than cooking at home. What do you think?","model":"I agree. Home cooking uses fresh food and less oil and salt. / I disagree. Restaurants can also serve healthy and balanced meals.","keywords":["agree","home","cooking","fresh","restaurants"]}]},{"id":5,"topic":"Public Transport","passage":"Many people in cities use public transport to go to work or school. Trains and buses can carry a lot of people at the same time. Using public transport is often cheaper than driving a car, and it also helps reduce air pollution. During busy hours in the morning, trains can become very crowded. Still, most people think public transport is useful and convenient.","illustration_1":"Several people are waiting at a bus stop. A woman is looking at her watch, and a man is reading a map on a sign.","illustration_2":"Inside a crowded train, some people are standing and holding the handles, and an old man is sitting and reading a newspaper.","questions":[{"q":"According to the passage, why is using public transport good for the environment?","model":"Because it helps reduce air pollution compared to driving a car.","keywords":["public","transport","reduce","pollution","environment"]},{"q":"Please look at illustration 1. What are the people doing at the bus stop?","model":"A woman is looking at her watch, and a man is reading a map on a sign.","keywords":["woman","watch","man","reading","map"]},{"q":"Please look at illustration 2. What are the people doing on the train?","model":"Some people are standing and holding the handles, and an old man is sitting and reading a newspaper.","keywords":["standing","holding","train","man","newspaper"]},{"q":"Do you often use trains or buses?","model":"Yes, I do. I take the train to school every morning. / No, I don't. My family usually goes everywhere by car.","keywords":["yes","train","bus","school","morning"]},{"q":"Some people say that everyone should use public transport instead of cars. What do you think?","model":"I agree. It reduces traffic and pollution in the city. / I disagree. Sometimes cars are faster and more comfortable for families.","keywords":["agree","public","transport","traffic","cars"]}]},{"id":6,"topic":"Part-Time Jobs","passage":"Some high school and college students have part-time jobs. They work at places like restaurants, convenience stores, and shops after school or on weekends. With a part-time job, students can earn their own money and learn how to work with other people. However, working too much can make it hard to study. Students need to find a good balance between their jobs and their schoolwork.","illustration_1":"A young woman is working at a coffee shop. She is making a hot drink behind the counter, and a customer is waiting in front of her.","illustration_2":"A boy is at his desk at home late at night. He looks very sleepy, and there are many textbooks open in front of him.","questions":[{"q":"According to the passage, what can students learn from a part-time job?","model":"They can earn their own money and learn how to work with other people.","keywords":["earn","money","learn","work","people"]},{"q":"Please look at illustration 1. What is the young woman doing?","model":"She is making a hot drink behind the counter while a customer waits in front of her.","keywords":["woman","making","drink","counter","customer"]},{"q":"Please look at illustration 2. What is the boy doing?","model":"He is studying at his desk late at night and looks very sleepy with many textbooks open.","keywords":["boy","studying","desk","sleepy","textbooks"]},{"q":"Do you want to have a part-time job in the future?","model":"Yes, I do. I want to earn money and gain some work experience. / No, I don't. I want to focus only on my studies and hobbies.","keywords":["yes","part-time","job","money","experience"]},{"q":"Some people say that students should not have part-time jobs. What do you think?","model":"I agree. Students should spend their time studying and resting. / I disagree. A part-time job teaches useful skills and responsibility.","keywords":["agree","students","studying","job","skills"]}]},{"id":7,"topic":"Reading Habits","passage":"Reading books is a wonderful hobby for people of all ages. Books can teach us new things and take us to different worlds in our minds. Some people enjoy reading paper books, while others like to read on tablets or phones. Reading before bed can also help people relax and sleep better. Sadly, many young people today read fewer books than before.","illustration_1":"In a library, a girl is choosing a book from a tall shelf, and a boy is sitting at a table reading quietly.","illustration_2":"A woman is lying in bed at night. She is reading a book on a tablet, and a cup of tea is on the small table beside her.","questions":[{"q":"According to the passage, how can reading before bed help people?","model":"It can help people relax and sleep better.","keywords":["reading","bed","relax","sleep","better"]},{"q":"Please look at illustration 1. What are the children doing in the library?","model":"A girl is choosing a book from a tall shelf, and a boy is reading quietly at a table.","keywords":["girl","choosing","book","boy","reading"]},{"q":"Please look at illustration 2. What is the woman doing?","model":"She is lying in bed and reading a book on a tablet with a cup of tea beside her.","keywords":["woman","bed","reading","tablet","tea"]},{"q":"Do you like reading books?","model":"Yes, I do. I read a story or comic almost every night. / No, I don't. I prefer watching videos and playing games.","keywords":["yes","reading","books","night","story"]},{"q":"Some people say that reading paper books is better than reading on a screen. What do you think?","model":"I agree. Paper books are easier on the eyes and feel more real. / I disagree. Screens let you carry many books and read anywhere.","keywords":["agree","paper","books","eyes","screen"]}]},{"id":8,"topic":"Local Festivals","passage":"Local festivals are held in many towns during summer. At these festivals, people wear traditional clothes and enjoy dancing, music, and food. There are often small stands that sell games and snacks for children. Festivals are a good chance for people in the town to meet their neighbors and have fun together. Many families look forward to these events every year.","illustration_1":"At a summer festival, two girls in traditional clothes are dancing, and a group of people is watching and clapping.","illustration_2":"At a food stand, a man is cooking grilled food, and a boy is pointing at the snacks and smiling.","questions":[{"q":"According to the passage, why are festivals a good chance for people in the town?","model":"Because people can meet their neighbors and have fun together.","keywords":["festivals","meet","neighbors","fun","together"]},{"q":"Please look at illustration 1. What are the girls doing?","model":"Two girls in traditional clothes are dancing while a group of people watches and claps.","keywords":["girls","traditional","dancing","people","watching"]},{"q":"Please look at illustration 2. What are the man and the boy doing?","model":"The man is cooking grilled food, and the boy is pointing at the snacks and smiling.","keywords":["man","cooking","food","boy","pointing"]},{"q":"Do you enjoy going to festivals?","model":"Yes, I do. I love the food and the fireworks at summer festivals. / No, I don't. Festivals are usually too crowded and noisy for me.","keywords":["yes","festivals","food","summer","enjoy"]},{"q":"Some people say that local festivals are important for a town. What do you think?","model":"I agree. Festivals keep traditions alive and bring people together. / I disagree. They cost a lot of money and create a lot of trash.","keywords":["agree","festivals","traditions","together","town"]}]},{"id":9,"topic":"Saving Energy","passage":"Saving energy is something everyone can do at home. People can turn off the lights when they leave a room and unplug things they are not using. In summer, they can set the air conditioner to a warmer temperature to save power. Saving energy is good for the environment and also helps families save money. Small actions by many people can make a big difference.","illustration_1":"A boy is leaving his bedroom. He is turning off the light with his hand, and the room behind him is now dark.","illustration_2":"A father and his daughter are in the living room. The father is setting the air conditioner with a remote, and the daughter is opening a window.","questions":[{"q":"According to the passage, how can people save power in summer?","model":"They can set the air conditioner to a warmer temperature to save power.","keywords":["summer","air","conditioner","warmer","power"]},{"q":"Please look at illustration 1. What is the boy doing?","model":"He is turning off the light with his hand as he leaves his bedroom.","keywords":["boy","turning","light","leaving","bedroom"]},{"q":"Please look at illustration 2. What are the father and the daughter doing?","model":"The father is setting the air conditioner with a remote, and the daughter is opening a window.","keywords":["father","air","conditioner","daughter","window"]},{"q":"Do you try to save energy at home?","model":"Yes, I do. I always turn off the lights when I leave a room. / No, I don't. I often forget to switch off the lights and TV.","keywords":["yes","save","energy","lights","home"]},{"q":"Some people say that saving energy is everyone's job. What do you think?","model":"I agree. If everyone saves a little, we can protect the environment. / I disagree. Big companies use much more energy than families do.","keywords":["agree","saving","energy","environment","everyone"]}]},{"id":10,"topic":"Keeping Pets","passage":"Many people around the world keep pets in their homes. Dogs and cats are the most popular pets, but some people also keep birds or fish. Pets can make people feel happy and less lonely. However, taking care of a pet is not easy. Owners must feed their pets, keep them clean, and take them to the animal doctor when they are sick.","illustration_1":"A girl is in a park with her dog. She is throwing a ball, and the dog is running to catch it.","illustration_2":"In a living room, a boy is cleaning a fish tank, and a cat is sleeping on the sofa nearby.","questions":[{"q":"According to the passage, what must pet owners do to take care of their pets?","model":"They must feed their pets, keep them clean, and take them to the animal doctor when they are sick.","keywords":["owners","feed","clean","doctor","pets"]},{"q":"Please look at illustration 1. What is the girl doing?","model":"She is throwing a ball in the park, and her dog is running to catch it.","keywords":["girl","throwing","ball","dog","running"]},{"q":"Please look at illustration 2. What is the boy doing?","model":"He is cleaning a fish tank while a cat is sleeping on the sofa nearby.","keywords":["boy","cleaning","fish","tank","cat"]},{"q":"Do you have any pets at home?","model":"Yes, I do. I have a small dog, and I walk it every day. / No, I don't. My apartment does not allow animals inside.","keywords":["yes","pet","dog","home","walk"]},{"q":"Some people say that keeping a pet is good for children. What do you think?","model":"I agree. Caring for a pet teaches children kindness and responsibility. / I disagree. Pets take a lot of time and can be expensive for a family.","keywords":["agree","pet","children","responsibility","time"]}]}],"grade2":[{"id":1,"topic":"Online Learning","passage":"These days, more and more students study on the Internet instead of going to school. Online learning lets people take classes at home, so they can save time and money. Some students record their lessons and watch them again later. In this way, they can review difficult points as many times as they like. Online learning has become a useful way of studying for many people.","illustration":"A picture of a home study room. A boy is sitting at a desk and watching a lesson on a laptop. A girl is writing notes in a notebook. A woman is carrying a cup of coffee. A cat is sleeping on the sofa, and a clock on the wall shows nine o'clock.","questions":[{"q":"According to the passage, why can students save time and money?","model":"Because online learning lets them take classes at home.","keywords":["online","learning","classes","home"]},{"q":"Please look at the picture. How many people are studying in the room?","model":"Two people are studying in the room.","keywords":["two","people","studying"]},{"q":"Please look at the woman. What is she going to do?","model":"She is going to drink some coffee. / She is going to give the coffee to the boy.","keywords":["she","going","coffee","drink"]},{"q":"Some people say that studying online is better than studying at school. What do you think?","model":"I agree. Students can study at their own pace and review lessons anytime. / I disagree. At school, students can ask teachers and make friends easily.","keywords":["think","study","school","online"]},{"q":"Today, many schools use computers in their lessons. Do you think this is a good idea?","model":"Yes. Computers help students find information quickly and learn in fun ways. / No. Students may look at other things and stop paying attention.","keywords":["yes","no","computers","students","learn"]}]},{"id":2,"topic":"Working From Home","passage":"Working from home has become common in many countries. Instead of going to an office, people can do their jobs by using computers and the Internet at home. This way, they do not have to spend a long time traveling to work every morning. Some companies have found that their workers feel happier and finish more work. Because of these good points, many people now choose to work from home.","illustration":"A picture of a living room used as an office. A man is talking in an online meeting on his computer. A woman is typing on a keyboard at another desk. A child is drawing a picture on the floor. There is a printer next to the window, and a dog is lying near the door.","questions":[{"q":"According to the passage, why do many people choose to work from home?","model":"Because they do not have to spend a long time traveling to work.","keywords":["work","home","traveling","time"]},{"q":"Please look at the picture. How many people are using computers?","model":"Two people are using computers.","keywords":["two","people","computers"]},{"q":"Please look at the man. What is he doing?","model":"He is talking in an online meeting on his computer.","keywords":["he","talking","meeting","computer"]},{"q":"Some people say that working from home is better than working in an office. What do you think?","model":"I agree. People save travel time and can relax in their own homes. / I disagree. In an office, it is easier to talk with other workers.","keywords":["think","working","office","home"]},{"q":"Today, many companies let their workers stay at home. Do you think this trend will continue?","model":"Yes. Technology makes it easy to work anywhere, so more companies will allow it. / No. Some jobs need people to meet face to face at the office.","keywords":["yes","no","companies","workers","home"]}]},{"id":3,"topic":"Food Waste","passage":"Every day, a large amount of food is thrown away around the world. Restaurants and stores often prepare too much food, and some of it is never eaten. This food waste is a serious problem because making food uses a lot of water and energy. Now, some shops sell food that is close to its sell-by date at lower prices. In this way, they try to reduce the amount of food waste.","illustration":"A picture of a supermarket. A woman is putting vegetables into a shopping basket. A man is reading the date on a package of meat. A store clerk is placing discount stickers on some bread. Two children are looking at fruit, and a sign above the shelf says \"Save Food.\"","questions":[{"q":"According to the passage, how do some shops try to reduce food waste?","model":"They sell food that is close to its sell-by date at lower prices.","keywords":["sell","food","lower","prices"]},{"q":"Please look at the picture. How many children are looking at fruit?","model":"Two children are looking at fruit.","keywords":["two","children","fruit"]},{"q":"Please look at the store clerk. What is he going to do?","model":"He is going to put discount stickers on the bread. / He is going to lower the price of the bread.","keywords":["he","going","stickers","bread"]},{"q":"Some people say that restaurants make too much food. What do you think?","model":"I agree. Many restaurants throw away food that no one eats. / I disagree. Restaurants need enough food so that every customer can order.","keywords":["think","restaurants","food","waste"]},{"q":"Today, food waste is a big problem. Do you think people should try harder to stop it?","model":"Yes. Wasting food also wastes water and energy, so we must be careful. / No. It is difficult for busy people to think about food waste every day.","keywords":["yes","no","food","waste","stop"]}]},{"id":4,"topic":"Renewable Energy","passage":"Many countries are now trying to use more renewable energy such as solar power and wind power. Unlike oil and coal, these kinds of energy do not run out and do not make the air dirty. Because of this, they are better for the environment. Some homes even have solar panels on their roofs to make their own electricity. In the future, renewable energy will play an even bigger role in our lives.","illustration":"A picture of a town on a sunny day. A worker is putting solar panels on the roof of a house. A woman is riding an electric bicycle down the street. Two children are looking up at a large wind turbine on a hill. A man is washing his car, and birds are flying in the sky.","questions":[{"q":"According to the passage, why is renewable energy better for the environment?","model":"Because it does not run out and does not make the air dirty.","keywords":["renewable","energy","air","environment"]},{"q":"Please look at the picture. How many children are looking at the wind turbine?","model":"Two children are looking at the wind turbine.","keywords":["two","children","wind","turbine"]},{"q":"Please look at the worker. What is he doing?","model":"He is putting solar panels on the roof of a house.","keywords":["he","putting","solar","panels","roof"]},{"q":"Some people say that every home should use solar power. What do you think?","model":"I agree. Solar power is clean and helps families save money on electricity. / I disagree. Solar panels are expensive, so not every home can buy them.","keywords":["think","solar","power","home"]},{"q":"Today, many countries want to use more clean energy. Do you think they can stop using oil and coal?","model":"Yes. Technology is improving, so clean energy will become cheaper and easier to use. / No. Oil and coal are still needed for many factories and machines.","keywords":["yes","no","clean","energy","oil"]}]},{"id":5,"topic":"Tourism","passage":"Every year, millions of people travel to foreign countries as tourists. By visiting new places, they can enjoy different food, culture, and history. Tourism is also good for local towns because visitors spend money at hotels, shops, and restaurants. However, when too many tourists come at the same time, some places become crowded and noisy. For this reason, some cities are now thinking about how to welcome tourists in better ways.","illustration":"A picture of a famous old temple. A tour guide is holding a small flag and explaining something to a group. A woman is taking a photograph of the building. A man is buying a souvenir from a shop. Two tourists are looking at a map, and pigeons are walking on the ground.","questions":[{"q":"According to the passage, why is tourism good for local towns?","model":"Because visitors spend money at hotels, shops, and restaurants.","keywords":["tourists","spend","money","shops"]},{"q":"Please look at the picture. How many tourists are looking at a map?","model":"Two tourists are looking at a map.","keywords":["two","tourists","map"]},{"q":"Please look at the woman. What is she going to do?","model":"She is going to take a photograph of the building. / She is going to take a picture of the temple.","keywords":["she","going","photograph","building"]},{"q":"Some people say that traveling abroad is the best way to learn about other cultures. What do you think?","model":"I agree. When we visit a country, we can see its real life and customs. / I disagree. We can also learn about cultures through books and the Internet.","keywords":["think","traveling","cultures","learn"]},{"q":"Today, some popular places have too many tourists. Do you think cities should limit the number of visitors?","model":"Yes. Fewer visitors would keep the places clean and quiet for everyone. / No. Tourists bring money that helps the local people and shops.","keywords":["yes","no","cities","tourists","limit"]}]},{"id":6,"topic":"Volunteering","passage":"Volunteering has become popular among people of all ages. Volunteers help others without receiving money, for example by cleaning parks or teaching children. Through these activities, they can meet new people and learn useful skills. Many volunteers also say that helping others makes them feel happy. Because of these good points, more schools and companies now encourage their members to take part in volunteer work.","illustration":"A picture of a park on a weekend. A group of volunteers is picking up trash and putting it into bags. A woman is planting flowers near a bench. An old man is teaching two children how to plant a tree. A dog is running on the grass, and the sun is shining brightly.","questions":[{"q":"According to the passage, why do many volunteers feel happy?","model":"Because helping others makes them feel happy.","keywords":["helping","others","happy","volunteers"]},{"q":"Please look at the picture. How many children is the old man teaching?","model":"He is teaching two children.","keywords":["two","children","teaching"]},{"q":"Please look at the woman. What is she doing?","model":"She is planting flowers near a bench.","keywords":["she","planting","flowers","bench"]},{"q":"Some people say that students should do volunteer work. What do you think?","model":"I agree. Volunteering teaches students to care about their community. / I disagree. Students are busy with study, so they may not have enough time.","keywords":["think","students","volunteer","work"]},{"q":"Today, many companies support volunteer activities. Do you think this is a good trend?","model":"Yes. It helps society and also lets workers feel proud of their company. / No. Some workers may feel forced to join and lose their free time.","keywords":["yes","no","companies","volunteer","activities"]}]},{"id":7,"topic":"Social Media","passage":"Social media has changed the way people share information. By using their smartphones, people can post messages and photos and connect with friends far away. Companies also use social media to tell customers about their products. However, some people spend too much time on social media and forget about other things in their lives. For this reason, it is important to use social media in a careful and balanced way.","illustration":"A picture of a cafe. A young woman is taking a photo of her cake with her smartphone. A man is reading messages on his phone while drinking coffee. Two friends are laughing and looking at the same screen. A waiter is carrying a tray, and a poster on the wall shows the cafe's name.","questions":[{"q":"According to the passage, why is it important to use social media carefully?","model":"Because some people spend too much time on it and forget about other things in their lives.","keywords":["social","media","time","carefully"]},{"q":"Please look at the picture. How many friends are looking at the same screen?","model":"Two friends are looking at the same screen.","keywords":["two","friends","screen"]},{"q":"Please look at the young woman. What is she going to do?","model":"She is going to post the photo of her cake online. / She is going to take a photo of her cake.","keywords":["she","going","photo","cake"]},{"q":"Some people say that social media brings people closer together. What do you think?","model":"I agree. People can stay in touch with friends even in faraway places. / I disagree. People may talk online but spend less time with real friends.","keywords":["think","social","media","people"]},{"q":"Today, many children use social media. Do you think this is a problem?","model":"Yes. Children may see bad information or spend too much time online. / No. Social media helps children learn and keep in touch with their friends.","keywords":["yes","no","children","social","media"]}]},{"id":8,"topic":"Healthy Lifestyles","passage":"Many people today are trying to live in healthier ways. They eat more vegetables, exercise regularly, and get enough sleep every night. A healthy lifestyle can help people avoid illnesses and feel more energetic during the day. Some workers even use their lunch breaks to walk or do light exercise. By making small changes in daily life, people can stay healthy for a long time.","illustration":"A picture of a city park in the morning. A man is jogging along a path. A woman is doing yoga on a mat. Two people are riding bicycles together. A young man is drinking water after running, and a food stand is selling fresh fruit and vegetables.","questions":[{"q":"According to the passage, how can a healthy lifestyle help people?","model":"It can help people avoid illnesses and feel more energetic during the day.","keywords":["healthy","avoid","illnesses","energetic"]},{"q":"Please look at the picture. How many people are riding bicycles?","model":"Two people are riding bicycles.","keywords":["two","people","bicycles"]},{"q":"Please look at the woman. What is she doing?","model":"She is doing yoga on a mat.","keywords":["she","doing","yoga","mat"]},{"q":"Some people say that everyone should exercise every day. What do you think?","model":"I agree. Daily exercise keeps the body strong and the mind fresh. / I disagree. Some people are too busy or tired to exercise every day.","keywords":["think","exercise","every","day"]},{"q":"Today, many people worry about their health. Do you think schools should teach more about healthy living?","model":"Yes. If children learn good habits early, they will stay healthy as adults. / No. Health should be taught mainly by families at home.","keywords":["yes","no","schools","healthy","living"]}]},{"id":9,"topic":"Public Libraries","passage":"Public libraries are useful places for people in a community. At libraries, people can borrow books for free and study in a quiet space. These days, many libraries also offer computers, e-books, and events for children. Because of this, libraries have become more than just places to read. They are places where people of all ages can learn and spend time together in their free time.","illustration":"A picture inside a library. A librarian is putting books back on a shelf. A boy is reading a picture book at a small table. A woman is using a computer near the window. Two students are studying together with their notebooks, and a sign on the desk says \"Quiet, Please.\"","questions":[{"q":"According to the passage, why have libraries become more than just places to read?","model":"Because they also offer computers, e-books, and events for children.","keywords":["libraries","computers","events","children"]},{"q":"Please look at the picture. How many students are studying together?","model":"Two students are studying together.","keywords":["two","students","studying"]},{"q":"Please look at the librarian. What is she going to do?","model":"She is going to put the books back on the shelf. / She is going to return the books to the shelf.","keywords":["she","going","books","shelf"]},{"q":"Some people say that libraries are not necessary because of the Internet. What do you think?","model":"I disagree. Libraries offer quiet spaces and free books that everyone can use. / I agree. People can now find most information easily on the Internet.","keywords":["think","libraries","internet","books"]},{"q":"Today, many people read books on their phones. Do you think paper books will disappear?","model":"No. Many people still enjoy holding real paper books. / Yes. Digital books are cheaper and easier to carry, so more people will use them.","keywords":["yes","no","paper","books","phones"]}]},{"id":10,"topic":"Recycling Technology","passage":"New technology is helping people recycle in smarter ways. Some machines can now sort plastic, glass, and paper quickly and correctly. Old bottles and cans are turned into new products such as bags and clothes. Thanks to this technology, less waste is buried in the ground, and fewer natural resources are used. Many people believe that better recycling technology will help protect the environment in the future.","illustration":"A picture of a recycling center. A worker is putting plastic bottles into a large machine. A woman is separating cans and paper into different boxes. A man is carrying a heavy bag of glass. Two students are watching the machines and taking notes, and a truck is waiting outside.","questions":[{"q":"According to the passage, what happens thanks to better recycling technology?","model":"Less waste is buried in the ground, and fewer natural resources are used.","keywords":["recycling","waste","resources","technology"]},{"q":"Please look at the picture. How many students are taking notes?","model":"Two students are taking notes.","keywords":["two","students","notes"]},{"q":"Please look at the woman. What is she doing?","model":"She is separating cans and paper into different boxes.","keywords":["she","separating","cans","paper"]},{"q":"Some people say that everyone should recycle at home. What do you think?","model":"I agree. If everyone recycles, we can save resources and reduce waste. / I disagree. Recycling takes time, and not everyone knows how to do it well.","keywords":["think","recycle","home","waste"]},{"q":"Today, technology is changing how we recycle. Do you think machines can solve our waste problem?","model":"Yes. Smart machines can sort waste quickly and turn it into new things. / No. Machines help, but people also need to use fewer things.","keywords":["yes","no","machines","waste","recycle"]}]}]};


// ── Speech API wrappers ───────────────────────────────────────
const synth = window.speechSynthesis;
let recognition = null;
let isSpeaking = false;
let isListening = false;

let _cachedVoices = synth.getVoices();
if (typeof synth.onvoiceschanged !== 'undefined') {
  synth.onvoiceschanged = () => { _cachedVoices = synth.getVoices(); };
}

function getVoice(lang) {
  const voices = _cachedVoices.length ? _cachedVoices : synth.getVoices();
  return voices.find(v => v.lang.startsWith(lang)) || voices[0] || null;
}

function speakText(text, onEnd) {
  const doSpeak = (attempt) => {
    // The voice list can still be empty on the very first call in Chrome, until
    // the async 'voiceschanged' event fires. Speaking then makes the engine fall
    // back to the OS default voice — on a Japanese-locale machine that reads
    // English text in a Japanese voice ("doesn't read correctly"). Briefly wait
    // (bounded ~1.2s) for the list to populate, then speak regardless so it can
    // never hang. getVoice('en') is null only when the list is genuinely empty
    // (a loaded list with no English voice still returns voices[0]).
    if (!getVoice('en') && attempt < 10) {
      _cachedVoices = synth.getVoices();
      setTimeout(() => doSpeak(attempt + 1), 120);
      return;
    }
    const utt = new SpeechSynthesisUtterance(text);
    utt.lang = 'en-GB';
    utt.rate = 0.88;
    utt.pitch = 1.0;
    const voice = getVoice('en');
    if (voice) utt.voice = voice;
    utt.onstart  = () => { isSpeaking = true; };
    utt.onend    = () => { isSpeaking = false; if (onEnd) onEnd(); };
    utt.onerror  = () => { isSpeaking = false; if (onEnd) onEnd(); };
    synth.speak(utt);
  };
  if (isSpeaking) {
    synth.cancel();
    // cancel() is asynchronous in every major engine; speaking in the same
    // tick silently drops the new utterance (chromium issue 835373).
    setTimeout(() => doSpeak(0), 50);
  } else {
    doSpeak(0);
  }
}

function stopSpeaking() {
  synth.cancel();
  isSpeaking = false;
}

function startListening(onResult, onError) {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) { onError('not_supported'); return; }
  if (recognition) { try { recognition.abort(); } catch(e){} }
  recognition = new SR();
  recognition.lang = 'en-US';
  recognition.interimResults = false;
  recognition.maxAlternatives = 3;
  isListening = true;
  recognition.onresult = e => {
    isListening = false;
    const transcript = e.results[0][0].transcript;
    onResult(transcript.trim());
  };
  recognition.onerror = e => {
    isListening = false;
    onError(e.error);
  };
  recognition.onend = () => { isListening = false; };
  // recognition.start() throws synchronously if the engine is already running
  // (InvalidStateError 'already started') or otherwise can't start. Without this
  // guard the throw escapes handleRecord and the record button stays stuck on
  // "録音中..."; surface it through onError so the caller resets button state.
  try {
    recognition.start();
  } catch (e) {
    isListening = false;
    onError(e && e.name === 'InvalidStateError' ? 'already_started' : 'start_failed');
  }
}

function stopListening() {
  if (recognition) { try { recognition.stop(); } catch(e){} }
  isListening = false;
}

// ── Keyword scoring ───────────────────────────────────────────
function scoreAnswer(transcript, keywords) {
  if (!transcript) return { score: 0, matched: [], missed: keywords };
  const t = transcript.toLowerCase();
  const matched = [], missed = [];
  keywords.forEach(kw => {
    // check if any word in the keyword phrase appears in transcript
    const kwLower = kw.toLowerCase();
    if (t.includes(kwLower)) matched.push(kw);
    else missed.push(kw);
  });
  const score = Math.round((matched.length / keywords.length) * 100);
  return { score, matched, missed };
}

function gradeScore(score) {
  if (score >= 75) return { label: '優秀 ★★★', color: '#2E7D32', bg: '#E8F5E9' };
  if (score >= 50) return { label: '合格 ★★', color: '#E65100', bg: '#FFF3E0' };
  return { label: '要練習 ★', color: '#C62828', bg: '#FFEBEE' };
}

// ── Interview state ───────────────────────────────────────────
let ivLevel = null;       // '3' | 'P' | 'Q' | '2'
let ivSession = null;     // session object
let ivQIdx = 0;           // current question index
let ivResults = [];       // [{transcript, score, matched, missed}]
let ivPhase = 'passage';  // 'passage' | 'question'
let ivPassageRead = false;

const $iv = id => document.getElementById(id);

// ── Entry point: open interview from main menu ────────────────
function openInterviewMenu() {
  hideAll();
  show('iv-level-screen');
}

function startInterviewLevel(lv) {
  ivLevel = lv;
  ivResults = [];
  buildSessionMenu(lv);
  hide('iv-level-screen');
  show('iv-session-screen');
}

// Maps an app level code to its INTERVIEW_DATA key.
const IV_DATA_KEY = { '3': 'grade3', 'P': 'pre2', 'Q': 'pre2plus', '2': 'grade2' };

function buildSessionMenu(lv) {
  const sessions = INTERVIEW_DATA[IV_DATA_KEY[lv]];
  const grid = $iv('iv-session-grid');
  grid.innerHTML = '';
  const c = LEVEL_CFG[lv];
  sessions.forEach((s, i) => {
    const btn = document.createElement('button');
    btn.className = 'iv-session-btn';
    btn.style.borderLeft = '4px solid ' + c.accent;
    btn.innerHTML = '<span class="iv-session-num" style="background:' + c.accent + '">' + (i+1) + '</span>'
      + '<div><div class="iv-session-title">' + escHtml(s.topic) + '</div>'
      + '<div class="iv-session-desc">' + s.questions.length + '問</div></div>';
    btn.onclick = () => startSession(s);
    grid.appendChild(btn);
  });
}

function startSession(session) {
  ivSession = session;
  ivQIdx = 0;
  ivResults = [];
  ivPhase = 'passage';
  ivPassageRead = false;
  hide('iv-session-screen');
  show('iv-quiz-screen');
  stopSpeaking();
  renderPassagePhase();
}

// ── Passage phase ─────────────────────────────────────────────
function renderPassagePhase() {
  ivPhase = 'passage';
  const s = ivSession;
  const c = LEVEL_CFG[ivLevel];

  $iv('iv-topic-label').textContent = s.topic;
  $iv('iv-topic-label').style.color = c.accent;
  $iv('iv-phase-label').textContent = '問題カードを読んでください';
  $iv('iv-progress').textContent = 'パッセージ';

  let passageHTML = '<h2 style="font-size:20px;font-weight:700;margin-bottom:2px;">' + escHtml(s.topic) + '</h2>'
    + '<div style="width:64px;border-bottom:2px dotted var(--gold);margin:8px 0 14px;"></div>'
    + '<div class="iv-passage-text">' + escHtml(s.passage) + '</div>';

  // Two-illustration levels (準2級 / 準2級プラス) provide illustration_1/_2;
  // single-illustration levels (3級 / 2級) provide illustration.
  if (s.illustration_1) {
    passageHTML += '<div class="iv-illus-block"><div class="iv-illus-label">🖼 イラスト 1</div>'
      + '<div class="iv-illus-text">' + escHtml(s.illustration_1) + '</div></div>'
      + '<div class="iv-illus-block"><div class="iv-illus-label">🖼 イラスト 2</div>'
      + '<div class="iv-illus-text">' + escHtml(s.illustration_2) + '</div></div>';
  } else {
    passageHTML += '<div class="iv-illus-block"><div class="iv-illus-label">🖼 イラスト</div>'
      + '<div class="iv-illus-text">' + escHtml(s.illustration) + '</div></div>';
  }

  $iv('iv-content-area').innerHTML = passageHTML;

  $iv('iv-btn-listen').style.display = '';
  $iv('iv-btn-listen').textContent = '🔊 パッセージを聞く';
  $iv('iv-btn-listen').onclick = () => {
    $iv('iv-btn-listen').textContent = '🔊 読み上げ中...';
    $iv('iv-btn-listen').disabled = true;
    speakText(s.passage, () => {
      $iv('iv-btn-listen').textContent = '🔊 もう一度聞く';
      $iv('iv-btn-listen').disabled = false;
      ivPassageRead = true;
      $iv('iv-btn-next').style.display = '';
      $iv('iv-btn-next').style.background = cfg().accent;
    });
    ivPassageRead = true;
    $iv('iv-btn-next').style.display = '';
      $iv('iv-btn-next').style.background = cfg().accent;
  };

  $iv('iv-btn-record').style.display = 'none';
  $iv('iv-btn-reveal').style.display = 'none';
  $iv('iv-btn-next').style.display = 'none';
  $iv('iv-btn-next').style.background = cfg().accent;
  $iv('iv-btn-next').textContent = '質問へ進む →';
  $iv('iv-btn-next').onclick = () => { ivPhase = 'question'; ivRenderQuestion(); };
  $iv('iv-transcript-area').innerHTML = '';
  $iv('iv-transcript-area').classList.add('hidden');
  $iv('iv-feedback-area').innerHTML = '';
}

// ── Question phase ────────────────────────────────────────────
function ivRenderQuestion() {
  const s = ivSession;
  const q = s.questions[ivQIdx];
  const c = LEVEL_CFG[ivLevel];
  const total = s.questions.length;

  $iv('iv-phase-label').textContent = '質問 ' + (ivQIdx+1) + ' / ' + total;
  $iv('iv-progress').textContent = '質問 ' + (ivQIdx+1) + '/' + total;
  $iv('iv-topic-label').style.color = c.accent;

  // Show question
  $iv('iv-content-area').innerHTML =
    '<div class="iv-question-box" style="border-color:' + c.accent + '">'
    + '<div class="iv-q-label" style="color:' + c.accent + '">Q' + (ivQIdx+1) + '</div>'
    + '<div class="iv-q-text">' + escHtml(q.q) + '</div></div>';

  // Hear question button
  $iv('iv-btn-listen').style.display = '';
  $iv('iv-btn-listen').textContent = '🔊 質問を聞く';
  $iv('iv-btn-listen').disabled = false;
  $iv('iv-btn-listen').onclick = () => {
    $iv('iv-btn-listen').textContent = '🔊 読み上げ中...';
    $iv('iv-btn-listen').disabled = true;
    speakText(q.q, () => {
      $iv('iv-btn-listen').textContent = '🔊 もう一度聞く';
      $iv('iv-btn-listen').disabled = false;
    });
  };

  // Record button
  $iv('iv-btn-record').style.display = '';
  $iv('iv-btn-record').textContent = '🎤 回答を話す';
  $iv('iv-btn-record').disabled = false;
  $iv('iv-btn-record').className = 'iv-btn-record';
  $iv('iv-btn-record').onclick = handleRecord;

  $iv('iv-btn-reveal').style.display = 'none';
  $iv('iv-btn-next').style.display = 'none';
  $iv('iv-btn-next').style.background = cfg().accent;
  $iv('iv-transcript-area').innerHTML = '';
  $iv('iv-transcript-area').classList.remove('hidden');
  $iv('iv-feedback-area').innerHTML = '';
}

function handleRecord() {
  const q = ivSession.questions[ivQIdx];
  const c = LEVEL_CFG[ivLevel];

  stopSpeaking();
  $iv('iv-btn-record').textContent = '⏹ 録音中... (クリックで停止)';
  $iv('iv-btn-record').className = 'iv-btn-record recording';
  $iv('iv-transcript-area').innerHTML = '<span style="color:var(--text3)">聞いています...</span>';

  $iv('iv-btn-record').onclick = () => {
    stopListening();
    $iv('iv-btn-record').textContent = '🎤 もう一度話す';
    $iv('iv-btn-record').className = 'iv-btn-record';
    $iv('iv-btn-record').onclick = handleRecord;
    $iv('iv-transcript-area').innerHTML = '<span style="color:var(--text3)">録音を停止しました。</span>';
  };

  startListening(
    transcript => {
      const result = scoreAnswer(transcript, q.keywords);
      const grade = gradeScore(result.score);
      ivResults[ivQIdx] = { transcript, ...result };

      $iv('iv-transcript-area').innerHTML =
        '<div class="iv-transcript-label">あなたの回答：</div>'
        + '<div class="iv-transcript-text">' + escHtml(transcript) + '</div>';

      const matchedHTML = result.matched.length
        ? '<span class="kw-match">✓ ' + result.matched.map(escHtml).join('</span> <span class="kw-match">✓ ') + '</span>'
        : '<span style="color:var(--text3)">（キーワードなし）</span>';
      const missedHTML = result.missed.length
        ? result.missed.map(k => '<span class="kw-miss">' + escHtml(k) + '</span>').join(' ')
        : '<span style="color:#2E7D32">なし</span>';

      $iv('iv-feedback-area').innerHTML =
        '<div class="iv-score-pill" style="background:' + grade.bg + ';color:' + grade.color + '">'
        + grade.label + ' — ' + result.score + '%</div>'
        + '<div class="iv-kw-row"><span class="iv-kw-label">含まれたキーワード：</span>' + matchedHTML + '</div>'
        + '<div class="iv-kw-row"><span class="iv-kw-label">不足キーワード：</span>' + missedHTML + '</div>';

      $iv('iv-btn-record').textContent = '🎤 もう一度話す';
      $iv('iv-btn-record').className = 'iv-btn-record';
      $iv('iv-btn-record').onclick = handleRecord;
      $iv('iv-btn-reveal').style.display = '';
      $iv('iv-btn-next').style.display = '';
      $iv('iv-btn-next').style.background = cfg().accent;
      $iv('iv-btn-next').textContent = ivQIdx+1 >= ivSession.questions.length ? '結果を見る →' : '次の質問 →';
      $iv('iv-btn-next').onclick = () => {
        stopSpeaking();
        if (ivQIdx+1 >= ivSession.questions.length) showInterviewResults();
        else { ivQIdx++; ivRenderQuestion(); }
      };
    },
    err => {
      $iv('iv-btn-record').textContent = '🎤 もう一度話す';
      $iv('iv-btn-record').className = 'iv-btn-record';
      $iv('iv-btn-record').onclick = handleRecord;
      if (err === 'not_supported') {
        $iv('iv-transcript-area').innerHTML =
          '<div style="color:#C62828;font-size:13px">⚠️ このブラウザは音声認識に対応していません。Chrome をご利用ください。</div>';
      } else if (err === 'already_started' || err === 'start_failed') {
        $iv('iv-transcript-area').innerHTML =
          '<div style="color:#C62828;font-size:13px">⚠️ 録音を開始できませんでした。少し待ってから、もう一度「話す」を押してください。</div>';
      } else {
        $iv('iv-transcript-area').innerHTML =
          '<div style="color:#C62828;font-size:13px">⚠️ 音声を認識できませんでした。もう一度お試しください。（エラー：' + err + '）</div>';
      }
      $iv('iv-btn-reveal').style.display = '';
    }
  );
}

// ── Model answer reveal — handled inside initInterviewListeners ──

// ── Results screen ────────────────────────────────────────────
function showInterviewResults() {
  stopSpeaking();
  hide('iv-quiz-screen');
  show('iv-results-screen');
  const c = LEVEL_CFG[ivLevel];
  const answered = ivResults.filter(r => r);
  const avg = answered.length
    ? Math.round(answered.reduce((s,r) => s+r.score, 0) / answered.length)
    : 0;
  const grade = gradeScore(avg);

  $iv('iv-result-circle').style.background = 'conic-gradient(' + c.accent + ' 0 ' + avg + '%, #E4E0D4 ' + avg + '% 100%)';
  $iv('iv-result-circle').style.borderColor = 'transparent';
  $iv('iv-result-pct').textContent = avg + '%';
  $iv('iv-result-pct').style.color = c.accent;
  $iv('iv-result-grade').textContent = grade.label;
  $iv('iv-result-grade').style.color = grade.color;
  $iv('iv-result-topic').textContent = ivSession.topic;

  let detailHTML = '';
  ivSession.questions.forEach((q, i) => {
    const r = ivResults[i];
    const g = r ? gradeScore(r.score) : null;
    detailHTML += '<div class="iv-result-row">'
      + '<div class="iv-result-q">Q' + (i+1) + ': ' + escHtml(q.q) + '</div>'
      + (r
        ? '<div class="iv-result-transcript">' + escHtml(r.transcript) + '</div>'
          + '<div class="iv-score-pill" style="background:' + g.bg + ';color:' + g.color + ';display:inline-block;margin:4px 0">' + g.label + ' ' + r.score + '%</div>'
        : '<div style="color:var(--text3);font-size:13px">（回答なし）</div>')
      + '<div class="iv-model-answer" style="margin-top:6px"><div class="iv-model-label">模範解答：</div>'
      + '<div class="iv-model-text">' + escHtml(q.model) + '</div></div>'
      + '</div>';
  });
  $iv('iv-result-detail').innerHTML = detailHTML;
}

// ── Navigation wiring (deferred until DOM confirmed ready) ────
function initInterviewListeners() {
  const wire = (id, fn) => { const el = document.getElementById(id); if (el) el.onclick = fn; };

  wire('iv-back-to-menu',   () => { stopSpeaking(); stopListening(); hide('iv-level-screen'); goMenu(); });
  wire('iv-back-to-levels', () => { stopSpeaking(); hide('iv-session-screen'); show('iv-level-screen'); });
  wire('iv-quit-session',   async () => {
    stopSpeaking(); stopListening();
    const ok = await openModal('セッションを終了しますか？', '現在の進捗は保存されません。', '終了する');
    if (!ok) return;
    hide('iv-quiz-screen'); show('iv-session-screen'); buildSessionMenu(ivLevel);
  });
  wire('iv-results-retry',  () => { hide('iv-results-screen'); startSession(ivSession); });
  wire('iv-results-menu',   () => { stopSpeaking(); hide('iv-results-screen'); show('iv-session-screen'); buildSessionMenu(ivLevel); });
  wire('iv-btn-reveal', function() {
    const q = ivSession.questions[ivQIdx];
    const existing = document.getElementById('iv-feedback-area').innerHTML;
    document.getElementById('iv-feedback-area').innerHTML = existing
      + '<div class="iv-model-answer"><div class="iv-model-label">模範解答：</div>'
      + '<div class="iv-model-text">' + escHtml(q.model) + '</div></div>';
    this.style.display = 'none';
    speakText(q.model);
    const nextBtn = document.getElementById('iv-btn-next');
    if (nextBtn && nextBtn.style.display === 'none') {
      nextBtn.style.display = '';
      nextBtn.style.background = cfg().accent;
      nextBtn.textContent = ivQIdx+1 >= ivSession.questions.length ? '結果を見る →' : '次の質問 →';
      nextBtn.onclick = () => {
        stopSpeaking();
        if (ivQIdx+1 >= ivSession.questions.length) showInterviewResults();
        else { ivQIdx++; ivRenderQuestion(); }
      };
    }
  });

  // Level selector buttons
  document.querySelectorAll('.iv-level-btn').forEach(btn => {
    btn.addEventListener('click', function() {
      startInterviewLevel(this.getAttribute('data-iv-level'));
    });
  });

  console.log('[Interview] Listeners attached.');
  window._interviewLoaded = true;
}

// Run after DOM is ready (scripts are at end of body so DOM is ready,
// but use DOMContentLoaded as a safety net for cached/reordered loads)
console.log('[EikenApp] interview.js parsed OK — wiring listeners...');
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initInterviewListeners);
} else {
  initInterviewListeners();
}
